    const out: Member[] = [];
    for (let i = 0; i < all.length; i++) {
      if (kw.length > 0) {
        const hay = (all[i].name + ' ' + all[i].phone).toLowerCase();
        if (hay.indexOf(kw) < 0) {
          continue;
        }
      }
      out.push(all[i]);
