// Thin wrappers over built-in ArkUI dialogs/toasts. Keeps pages free of
// CustomDialogController wiring.
import { promptAction } from '@kit.ArkUI';
import { Theme } from '../common/Theme';

export class Ui {
  static toast(message: string): void {
    try {
      promptAction.showToast({ message: message, duration: 1800, bottom: 160 });
    } catch (e) {
      // ignore
    }
  }

  // Confirm dialog. Calls onConfirm when user accepts.
  static confirm(title: string, message: string, onConfirm: () => void): void {
    try {
      AlertDialog.show({
        title: title,
        message: message,
        autoCancel: true,
        alignment: DialogAlignment.Center,
        primaryButton: {
          value: '取消',
          fontColor: Theme.textMuted,
          action: () => {},
        },
        secondaryButton: {
          value: '确定',
          fontColor: Theme.brandPrimary,
          action: () => { onConfirm(); },
        },
      });
    } catch (e) {
      // fallback: just run the action
      onConfirm();
    }
  }

  // Simple option picker. options: display labels; onPick(index).
  static pick(title: string, options: string[], onPick: (index: number) => void): void {
    try {
      promptAction.showActionMenu({
        title: title,
        buttons: Ui.toButtons(options),
      }).then((result) => {
        if (result.index >= 0 && result.index < options.length) {
          onPick(result.index);
        }
      }).catch(() => {});
    } catch (e) {
      // ignore
    }
  }

  private static toButtons(options: string[]): Array<promptAction.Button> {
    const out: Array<promptAction.Button> = [];
    for (let i = 0; i < options.length && i < 6; i++) {
      out.push({ text: options[i], color: Theme.brandPrimary });
    }
    return out;
  }
}

