python3 <<'PY'
import re
errors = {
 "MemberDetailPage.ets":[59,211,226],
 "MemberEditPage.ets":[87,245],
 "CourseDetailPage.ets":[64,77],
 "CourseBookingPage.ets":[123,175],
 "PointRecordPage.ets":[92],
 "InventoryEditPage.ets":[85],
 "InventoryTransactionPage.ets":[80],
}
for f, lines in errors.items():
    src = open(f).read().split("\n")
    for ln in lines:
        idx = ln-1  # 0-based
        # scan upward to find the nearest component opener Row()/Column()
        kind = None
        for j in range(idx, max(-1, idx-40), -1):
            l = src[j]
            m = re.search(r'\b(Row|Column)\s*\(', l)
            if m:
                kind = m.group(1); break
        if kind == 'Row':
            if '.alignItems(HorizontalAlign.Center)' in src[idx]:
                src[idx] = src[idx].replace('.alignItems(HorizontalAlign.Center)','.alignItems(VerticalAlign.Center)')
                print(f"{f}:{ln} Row -> VerticalAlign")
            else:
                print(f"{f}:{ln} Row but no HorizontalAlign found: {src[idx].strip()}")
        else:
            print(f"{f}:{ln} kind={kind} (leave)")
    open(f,"w").write("\n".join(src))
PY

