129	      if (this.rows().length === 0) {
130	        Text('暂无积分流水')
131	          .fontSize(Theme.fontBody)
132	          .fontColor(Theme.textMuted)
133	          .width('100%')
134	          .textAlign(TextAlign.Center)
135	          .padding({ top: 28, bottom: 28 })
136	          .id('points-empty-state')
137	      } else {
138	        ForEach(this.rows(), (p: PointRow) => {
139	          Row() {
140	            Column() {
141	              Text(this.typeLabel(p.type, p.reason))
142	                .fontSize(Theme.fontBody)
143	                .fontColor(Theme.textTitle)
144	              Text(`${p.memberName} · ${TimeUtil.relativeDays(p.createdAt, TimeUtil.now())}`)
145	                .fontSize(Theme.fontCaption)
146	                .fontColor(Theme.textMuted)
147	                .margin({ top: 2 })
148	            }
149	            .layoutWeight(1)
150	            .alignItems(HorizontalAlign.Start)
151	
152	            Text(`${p.amount >= 0 ? '+' : ''}${p.amount}`)
153	              .fontSize(Theme.fontCardTitle)
154	              .fontWeight(FontWeight.Bold)
155	              .fontColor(p.amount >= 0 ? Theme.success : Theme.danger)
156	          }
157	          .width('100%')
158	          .padding({ top: 14, bottom: 14 })
159	          .border({ width: { bottom: 1 }, color: { bottom: Theme.cardDivider } })
160	          .id(`points-transaction-${p.id}`)
161	        }, (p: PointRow) => p.id)
162	      }
163	    }
164	    .width('100%')
165	    .padding({ left: 18, right: 18, top: 4, bottom: 4 })
166	    .backgroundColor(Theme.cardBg)
167	    .borderRadius(Theme.radiusCard)
168	    .border({ width: 1, color: Theme.borderSoft })
169	    .shadow({ radius: 28, color: 'rgba(74,48,36,0.10)', offsetX: 0, offsetY: 10 })
170	    .id('points-transaction-list')
171	  }
172	
173	  private rows(): PointRow[] {
174	    return AppStore.get().pointRows('', this.filter);
175	  }
176	
177	  private typeLabel(type: string, reason: string): string {
178	    if (reason.length > 0) {
179	      return reason;
180	    }
181	    if (type === 'checkin') {
182	      return '签到奖励';
183	    }
184	    if (type === 'earn') {
185	      return '积分增加';
186	    }
187	    if (type === 'spend') {
188	      return '积分消耗';
189	    }
190	    return '积分调整';
191	  }
192	
193	  // Quick check-in for the most recently visited / first member (no picker on this surface).
194	  private doQuickCheckin(): void {
195	    const store = AppStore.get();
196	    const list = store.getMembers();
197	    if (list.length === 0) {
198	      Ui.toast('请先添加会员');
199	      this.onOpen({ target: 'member-edit' });
200	      return;
201	    }
202	    // Pick the member with the earliest lastVisitAt (most in need) for a quick check-in.
203	    let target = list[0];
204	    for (let i = 1; i < list.length; i++) {
205	      if (list[i].lastVisitAt < target.lastVisitAt) {
206	        target = list[i];
207	      }
208	    }
209	    if (store.hasCheckedInToday(target.id)) {
210	      Ui.toast(`${target.name} 今日已签到`);
211	      return;
212	    }
213	    const pts = store.getSettings().checkinPoints;
214	    store.applyPointTx(target.id, 'checkin', pts, '每日签到', 'checkin', '');
215	    store.touchMember(target.id, TimeUtil.now(), 0);
216	    Ui.toast(`${target.name} 签到成功 +${pts}`);
217	  }
218	}

